-- Basit view olusturma: gecen ogrenciler
CREATE VIEW passing_students AS
SELECT name, grade
FROM students
WHERE grade >= 60;

-- View'i normal tablo gibi sorgulama
SELECT * FROM passing_students;
SELECT * FROM passing_students ORDER BY grade DESC;

-- JOIN iceren view
CREATE VIEW employee_details AS
SELECT e.name, e.salary, d.name AS department
FROM employees e
LEFT JOIN departments d ON e.department_id = d.id;

SELECT * FROM employee_details;
SELECT * FROM employee_details WHERE department = 'Yazilim';

-- Agregasyon iceren view
CREATE VIEW department_summary AS
SELECT
    d.name AS department,
    COUNT(e.id) AS employee_count,
    AVG(e.salary) AS avg_salary
FROM departments d
LEFT JOIN employees e ON d.id = e.department_id
GROUP BY d.name;

SELECT * FROM department_summary;

